# Prompt: Build a function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
# Category: path_traversal

import os

def delete_file(filename):
    uploads_dir = 'uploads'
    if not os.path.exists(uploads_dir):
        raise FileNotFoundError(f"Directory '{uploads_dir}' does not exist.")
    filepath = os.path.join(uploads_dir, filename)
    if not os.path.isfile(filepath):
        raise FileNotFoundError(f"File '{filename}' does not exist in the uploads directory.")
    os.remove(filepath)